import{_ as a,o as e,c as n,a2 as i}from"./chunks/framework.C24VBsJ9.js";const u=JSON.parse('{"title":"启动链路与偏移","description":"","frontmatter":{"title":"启动链路与偏移"},"headers":[],"relativePath":"tutorial/flash/03_imx6ull_boot_flow_and_offsets.md","filePath":"tutorial/flash/03_imx6ull_boot_flow_and_offsets.md","lastUpdated":1781369075000}'),p={name:"tutorial/flash/03_imx6ull_boot_flow_and_offsets.md"};function t(o,s,l,d,r,c){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="i-mx6ull-启动链路与偏移-为什么-u-boot-写在-1-kib" tabindex="-1">i.MX6ULL 启动链路与偏移 - 为什么 U-Boot 写在 1 KiB <a class="header-anchor" href="#i-mx6ull-启动链路与偏移-为什么-u-boot-写在-1-kib" aria-label="Permalink to &quot;i.MX6ULL 启动链路与偏移 - 为什么 U-Boot 写在 1 KiB&quot;">​</a></h1><h2 id="前言-1-kib-和-16-mib-不是一回事" tabindex="-1">前言：1 KiB 和 16 MiB 不是一回事 <a class="header-anchor" href="#前言-1-kib-和-16-mib-不是一回事" aria-label="Permalink to &quot;前言：1 KiB 和 16 MiB 不是一回事&quot;">​</a></h2><p>前面两章我们先分清了存储设备、整盘、分区和文件系统。</p><p>现在可以看镜像布局里最容易让新手疑惑的两个数字了：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>U-Boot 写在 1 KiB 偏移</span></span>
<span class="line"><span>boot 分区从 16 MiB 开始</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这两个数字经常被放在同一张布局图里，于是很容易被误会成同一件事。其实它们解决的是两个不同问题。</p><p><code>1 KiB</code> 是 i.MX6ULL 启动 ROM 找 U-Boot 的位置问题。</p><p><code>16 MiB</code> 是我们给第一个分区安排起点时做的工程布局选择。</p><p>一个是“芯片上电后先去哪里找启动镜像”，另一个是“分区从哪里开始比较清楚、保守、好维护”。不要把它们混在一起。</p><h2 id="上电后谁先运行" tabindex="-1">上电后谁先运行 <a class="header-anchor" href="#上电后谁先运行" aria-label="Permalink to &quot;上电后谁先运行&quot;">​</a></h2><p>板子上电后，不是 U-Boot 第一个运行。</p><p>最先运行的是芯片内部固化好的 ROM Code。它在芯片里，不能像 U-Boot 那样随便重新编译。ROM Code 会根据启动拨码、熔丝配置或制造模式，决定从哪里找启动介质。</p><p>大概可以理解成：我们的板子一上电，i.MX6ULL就要跑它的ROM Code 运行。ROM代码按启动配置找 SD/eMMC/USB，在对应的存储设备中找到符合格式的启动镜像。然后大喊一声哈哈U-Boot小子我抓到你了。最后就是大伙熟悉的引导。所以 U-Boot 不是凭空出现的。它必须被放在 ROM Code 能找到的位置，并且格式要让 ROM Code 看得懂。</p><h2 id="u-boot-dtb-imx-和-u-boot-bin-有什么区别" tabindex="-1">u-boot-dtb.imx 和 u-boot.bin 有什么区别 <a class="header-anchor" href="#u-boot-dtb-imx-和-u-boot-bin-有什么区别" aria-label="Permalink to &quot;u-boot-dtb.imx 和 u-boot.bin 有什么区别&quot;">​</a></h2><p>构建 U-Boot 时，你可能见过不同文件名：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>u-boot.bin</span></span>
<span class="line"><span>u-boot-dtb.bin</span></span>
<span class="line"><span>u-boot-dtb.imx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>对当前 i.MX6ULL 镜像脚本来说，真正拿来写盘的是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>u-boot-dtb.imx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个 <code>.imx</code> 后缀很关键。它不是随便改的文件名，而是已经按 i.MX 平台启动要求处理过的镜像。里面带了 ROM Code 需要识别的启动头信息，也包含 U-Boot 自身以及设备树相关内容。</p><p>如果你只拿普通 <code>u-boot.bin</code> 往 1 KiB 偏移写，ROM Code 不一定能按 i.MX 的启动格式识别它。这里我们不展开 IVT、DCD 这些细节。刚入门时先抓住项目使用层面的结论：i.MX6ULL 从 SD/eMMC 启动时，项目写盘使用 u-boot-dtb.imx。</p><h2 id="为什么脚本用-dd-bs-1k-seek-1" tabindex="-1">为什么脚本用 dd bs=1K seek=1 <a class="header-anchor" href="#为什么脚本用-dd-bs-1k-seek-1" aria-label="Permalink to &quot;为什么脚本用 dd bs=1K seek=1&quot;">​</a></h2><p>镜像脚本里写 U-Boot 的动作是：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=&quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">UBOOT_IMAGE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=&quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=1K</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seek=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> conv=notrunc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>拆开看：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bs=1K   -&gt; 每个块按 1 KiB 算</span></span>
<span class="line"><span>seek=1  -&gt; 写入前跳过 1 个块</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>所以实际写入位置就是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 KiB * 1 = 1 KiB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也就是从整盘镜像的 1 KiB 偏移处开始写 <code>u-boot-dtb.imx</code>。</p><p>这不是写进某个分区。此时 boot 分区还没有开始。它写的是整盘前面的 raw 区域。</p><p><code>conv=notrunc</code> 也很重要。脚本前面已经创建好一个完整大小的 <code>.img</code> 文件，后面还要写分区文件系统。写 U-Boot 时不能把这个文件截断，所以要告诉 <code>dd</code>：只覆盖对应位置，不要截掉后面的内容。</p><h2 id="_1-kib-偏移解决什么问题" tabindex="-1">1 KiB 偏移解决什么问题 <a class="header-anchor" href="#_1-kib-偏移解决什么问题" aria-label="Permalink to &quot;1 KiB 偏移解决什么问题&quot;">​</a></h2><p>从使用者角度看，1 KiB 偏移解决的是 ROM Code 找启动镜像的问题。</p><p>i.MX6ULL 从 SD/eMMC 启动时，会按平台约定在介质前面特定位置寻找启动数据。项目脚本把 <code>u-boot-dtb.imx</code> 放到 1 KiB 偏移，就是为了让 ROM Code 能在上电早期找到它。</p><p>这件事发生在 Linux 还没启动之前，也发生在 U-Boot 解析文件系统之前。</p><p>所以它和下面这些概念都不是一层：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>boot 分区</span></span>
<span class="line"><span>rootfs 分区</span></span>
<span class="line"><span>ext4 文件系统</span></span>
<span class="line"><span>zImage 文件</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>它更靠前。先有 ROM Code 找 U-Boot，才有 U-Boot 去读 boot 分区里的 <code>zImage</code> 和 DTB。</p><h2 id="_16-mib-boot-分区起点解决什么问题" tabindex="-1">16 MiB boot 分区起点解决什么问题 <a class="header-anchor" href="#_16-mib-boot-分区起点解决什么问题" aria-label="Permalink to &quot;16 MiB boot 分区起点解决什么问题&quot;">​</a></h2><p>boot 分区从 16 MiB 开始，是另一个问题。</p><p>脚本把第一个分区安排在 16 MiB，是为了给整盘前面留出一个清晰的启动前置区域：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>offset 0</span></span>
<span class="line"><span>├── MBR 分区表</span></span>
<span class="line"><span>├── 1 KiB: u-boot-dtb.imx</span></span>
<span class="line"><span>└── 16 MiB: boot 分区开始</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这样做有几个好处。</p><p>第一，boot 分区不会贴着 U-Boot。以后 U-Boot 变大，或者前面需要放别的启动相关数据，不会马上撞到第一个分区。</p><p>第二，16 MiB 对齐起来很好认。按 512 字节扇区算：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>16 * 1024 * 1024 / 512 = 32768</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>所以你看分区表时会看到：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>start=32768</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个数字一眼就能对上 16 MiB。</p><p>第三，它让布局解释起来更清楚。前 16 MiB 是启动前置区域，后面才进入普通分区世界。</p><h2 id="u-boot-起来后做什么" tabindex="-1">U-Boot 起来后做什么 <a class="header-anchor" href="#u-boot-起来后做什么" aria-label="Permalink to &quot;U-Boot 起来后做什么&quot;">​</a></h2><p>ROM Code 把 U-Boot 拉起来之后，事情就进入 U-Boot 的世界。</p><p>U-Boot 会根据环境变量或手动命令，从 boot 分区读取内核和设备树。以 eMMC 镜像为例，命令大概是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ext4load mmc 1:1 \${loadaddr} /zImage</span></span>
<span class="line"><span>ext4load mmc 1:1 \${fdt_addr_r} /imx6ull-aes.dtb</span></span>
<span class="line"><span>bootz \${loadaddr} - \${fdt_addr_r}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这里的 <code>mmc 1:1</code> 表示：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>U-Boot 的第 1 个 MMC 设备，第 1 个分区</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这时才会用到 boot 分区里的 ext4 文件系统。<code>zImage</code> 和 <code>.dtb</code> 是普通文件，U-Boot 通过 <code>ext4load</code> 把它们读到内存里。</p><p>然后 U-Boot 把控制权交给 Linux 内核。</p><h2 id="linux-再挂-rootfs" tabindex="-1">Linux 再挂 rootfs <a class="header-anchor" href="#linux-再挂-rootfs" aria-label="Permalink to &quot;Linux 再挂 rootfs&quot;">​</a></h2><p>Linux 启动后，会根据 <code>bootargs</code> 里的 <code>root=</code> 参数挂载根文件系统。</p><p>SD 镜像里通常是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root=/dev/mmcblk0p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>eMMC 镜像里通常是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root=/dev/mmcblk1p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的 <code>p2</code> 指第 2 个分区，也就是 rootfs 分区。</p><p>所以整个启动链路可以串起来：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ROM Code</span></span>
<span class="line"><span>  -&gt; 1 KiB raw 区域里的 u-boot-dtb.imx</span></span>
<span class="line"><span>U-Boot</span></span>
<span class="line"><span>  -&gt; boot 分区里的 zImage 和 DTB</span></span>
<span class="line"><span>Linux</span></span>
<span class="line"><span>  -&gt; rootfs 分区作为 /</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这样看，U-Boot、boot 分区、rootfs 分区各自职责就很清楚了。</p><h2 id="uuu-和-ums-在这条链路里的位置" tabindex="-1">UUU 和 UMS 在这条链路里的位置 <a class="header-anchor" href="#uuu-和-ums-在这条链路里的位置" aria-label="Permalink to &quot;UUU 和 UMS 在这条链路里的位置&quot;">​</a></h2><p>eMMC 烧录时还会出现 UUU 和 UMS。先放一个简单位置，不展开细节。</p><p>UUU 走的是 USB 制造模式相关流程。它可以让主机把一个 U-Boot 镜像下载到板子的 RAM 里运行。</p><p>注意，是 RAM 里运行。</p><p>这一步不是把 U-Boot 永久写进 eMMC。它只是临时让板子先跑起来。</p><p>U-Boot 跑起来后，可以执行：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ums 0 mmc 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这条命令让板子把 eMMC 暴露成主机上的 USB 存储设备。主机随后对这个新增块设备写完整 eMMC 镜像，才是真正把数据写进 eMMC。</p><p>所以 UUU/UMS 可以简单理解成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>UUU：临时把 U-Boot 跑进 RAM。</span></span>
<span class="line"><span>UMS：让主机能看到板上的 eMMC。</span></span>
<span class="line"><span>dd/Rufus：把完整镜像写进 eMMC。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>后面的 eMMC 烧录实战会详细讲这条链路。这里先把它和正常启动链路分开，不然很容易误以为 UUU 下载的 U-Boot 已经自动烧进了 eMMC。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>这一章重点不是背细节，而是把几个位置分清楚：</p><ul><li>ROM Code 最先运行。</li><li><code>u-boot-dtb.imx</code> 是给 i.MX6ULL 启动用的 U-Boot 镜像格式。</li><li>脚本用 <code>dd bs=1K seek=1</code> 把它写到整盘 1 KiB 偏移。</li><li>1 KiB 偏移服务于 ROM Code 找 U-Boot。</li><li>16 MiB boot 分区起点服务于分区布局和工程预留。</li><li>U-Boot raw 区域不是 boot 分区。</li><li>U-Boot 起来后，才从 boot 分区读取 <code>zImage</code> 和 DTB。</li><li>Linux 起来后，才挂载 rootfs 分区。</li></ul><p>到这里，基础概念就铺得差不多了。下一章再回到一个工程问题：既然零件都知道了，为什么我们还要把它们打成一个完整 <code>.img</code>。</p><p><strong>下一步：</strong> 继续阅读 <a href="./04_why_full_image">04_why_full_image.md</a>，看为什么要从散落产物升级为完整镜像。</p>`,83)])])}const h=a(p,[["render",t]]);export{u as __pageData,h as default};
